import React, { useEffect, useState } from 'react';
import { Box, Heading, Button, Table, Tbody, Td, Th, Thead, Tr, useToast } from '@chakra-ui/react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';

const UserDashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [startDate, setStartDate] = useState(new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })));
  const [endDate, setEndDate] = useState(new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })));
  const navigate = useNavigate();
  const toast = useToast();

  // Fetch tasks for selected date range
  const fetchTasks = async () => {
    try {
      const token = localStorage.getItem('authToken');
      if (!token) {
        throw new Error('No authentication token found');
      }

      const response = await axios.get('http://localhost:5000/api/tasks', {
        params: {
          startDate: startDate ? startDate.toISOString() : null,
          endDate: endDate ? endDate.toISOString() : null,
        },
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      setTasks(response.data);
    } catch (error) {
      console.error('Error fetching tasks:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  useEffect(() => {
    const token = localStorage.getItem('authToken');
    if (!token) {
      navigate('/');
      return;
    }

    // Verify user identity
    const verifyUser = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/auth/me', {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        });

        if (response.data.role !== 'teamMember') {
          toast({
            title: 'Unauthorized',
            description: 'You do not have permission to view this page.',
            status: 'error',
            duration: 3000,
            isClosable: true,
          });
          navigate('/');
        } else {
          // Automatically fetch today's tasks when the user is authorized
          fetchTasks();
        }
      } catch (error) {
        console.error('User verification failed:', error);
        localStorage.removeItem('authToken');
        navigate('/');
      }
    };

    verifyUser();
  }, [navigate, toast]);

  return (
    <Box maxW="80%" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={6} textAlign="center">
        User Dashboard
      </Heading>

      {/* Date Range Picker */}
      <Box mb={6} display="flex" justifyContent="center" alignItems="center">
        <DatePicker
          selected={startDate}
          onChange={(date) => setStartDate(date)}
          selectsStart
          startDate={startDate}
          endDate={endDate}
          placeholderText="Start Date"
          isClearable
        />
        <Box mx={4}>to</Box>
        <DatePicker
          selected={endDate}
          onChange={(date) => setEndDate(date)}
          selectsEnd
          startDate={startDate}
          endDate={endDate}
          placeholderText="End Date"
          isClearable
        />
        <Button colorScheme="teal" ml={4} onClick={fetchTasks}>
          Fetch Tasks
        </Button>
      </Box>

      {/* Task Log Table */}
      <Table variant="striped" colorScheme="teal" mt={4}>
        <Thead>
          <Tr>
            <Th>Task ID</Th>
            <Th>Queue</Th>
            <Th>Time Spent (s)</Th>
            <Th>Comment</Th>
            <Th>Date Completed</Th>
          </Tr>
        </Thead>
        <Tbody>
          {tasks.map((task) => (
            <Tr key={task._id}>
              <Td>{task.taskId}</Td>
              <Td>{task.queue}</Td>
              <Td>{task.timeSpent}</Td>
              <Td>{task.comment}</Td>
              <Td>{new Date(task.createdAt).toLocaleString()}</Td>
            </Tr>
          ))}
        </Tbody>
      </Table>
    </Box>
  );
};

export default UserDashboard;
